mapper.select:
SELECT ur.id, r.role_code, r.role_name, ur.start_time, ur.end_time, ur.enable_status, ur.create_time, ur.create_by, ur.update_time, ur.update_by FROM iam_user_role ur INNER JOIN iam_role r ON r.role_code = ur.role_code WHERE ur.deleted = 0 AND r.deleted = 0 AND ur.user_code = #{userCode}
AND ur.role_code = #{roleCode}
ORDER BY ur.sort ASC, ur.id ASC
